import{_ as a,c as e,o as r,a5 as i}from"./chunks/framework.DwbewbAn.js";const R=JSON.parse('{"title":"基数树(Radix Tree)","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据结构/Radix Tree/Radix Tree.md","filePath":"packages/doc/src/数据结构/Radix Tree/Radix Tree.md","lastUpdated":1704643216000}'),t={name:"doc/数据结构/Radix Tree/Radix Tree.md"},d=i('<h1 id="基数树-radix-tree" tabindex="-1">基数树(Radix Tree) <a class="header-anchor" href="#基数树-radix-tree" aria-label="Permalink to &quot;基数树(Radix Tree)&quot;">​</a></h1><p><strong>简介</strong>Radix树与Trie树的思想有点类似，甚至可以把Trie树看为一个基为26的Radix树。（也可以把Radix树看做是Tire树的变异），只不过Radix正对的整数，Trie针对的是字符串</p><ul><li><a href="https://ditanshow.com/articles/p/161.html#1" target="_blank" rel="noreferrer">1. 基数树概述</a></li><li><a href="https://ditanshow.com/articles/p/161.html#2" target="_blank" rel="noreferrer">2. 插入、删除操作</a></li><li><a href="https://ditanshow.com/articles/p/161.html#3-radixtree" target="_blank" rel="noreferrer">3. RadixTree应用</a></li><li><a href="https://ditanshow.com/articles/p/161.html#4" target="_blank" rel="noreferrer">4. 总结</a></li></ul><h2 id="_1-基数树概述" tabindex="-1">1. 基数树概述 <a class="header-anchor" href="#_1-基数树概述" aria-label="Permalink to &quot;1. 基数树概述&quot;">​</a></h2><p>对于长整型数据的映射，如何解决Hash冲突和Hash表大小的设计是一个很头疼的问题。</p><p>radix树就是针对这种稀疏的长整型数据查找，能快速且节省空间地完成映射。借助于Radix树，我们可以实现对于长整型数据类型的路由。</p><p>利用radix树可以根据一个长整型（比如一个长ID）快速查找到其对应的对象指针。这比用hash映射来的简单，也更节省空间，使用hash映射hash函数难以设计，不恰当的hash函数可能增大冲突，或浪费空间。</p><p>radix tree是一种多叉搜索树，树的叶子结点是实际的数据条目。每个结点有一个固定的指针指向子结点（每个指针称为槽slot，n为划分的基的大小）</p><h2 id="_2-插入、删除操作" tabindex="-1">2. 插入、删除操作 <a class="header-anchor" href="#_2-插入、删除操作" aria-label="Permalink to &quot;2. 插入、删除操作&quot;">​</a></h2><p>radix Tree(基数树) 其实就差不多是传统的二叉树，只是在寻找方式上，利用比如一个unsigned int的类型的每一个比特位作为树节点的判断。</p><p>比如一个数1000101010101010010101010010101010，那么按照Radix 树的插入就是在根节点，如果遇到0，就指向左节点，如果遇到1就指向右节点，在插入过程中构造树节点，在删除过程中删除树节点。如果觉得太多的调用Malloc的话，可以采用池化技术，预先分配多个节点。</p><p>使用一个比特位判断，会使树的高度过高，非叶节点过多。故在实际应用中，我们一般是使用多个比特位作为树节点的判断，但多比特位会使节点的子节点槽变多，增大节点的体积，一般选用2个或4个比特位作为树节点即可。</p><p>如图： <img src="https://ditanshow.com/media/articles/images/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84/2020-02-18-1.png" alt="img"></p><p>插入操作：我们在插入一个新节点时，我们根据数据的比特位，在树中向下查找，若没有相应结点，则生成相应结点，直到数据的比特位访问完，则建立叶节点映射相应的对象。</p><p>删除操作：我们可以“惰性删除”，即沿着路径查找到叶节点后，直接删除叶节点，中间的非叶节点不删除。</p><h2 id="_3-radixtree应用" tabindex="-1">3. RadixTree应用 <a class="header-anchor" href="#_3-radixtree应用" aria-label="Permalink to &quot;3. RadixTree应用&quot;">​</a></h2><p>Linux基数树（radix tree）是将long整数键值与指针相关联的机制，它存储有效率，并且可快速查询，用于整数值与指针的映射（如：IDR机制）、内存管理等。</p><p>IDR（ID Radix）机制是将对象的身份鉴别号整数值ID与对象指针建立关联表，完成从ID与指针之间的相互转换。IDR机制使用radix树状结构作为由id进行索引获取指针的稀疏数组，通过使用位图可以快速分配新的ID，IDR机制避免了使用固定尺寸的数组存放指针。IDR机制的API函数在lib/idr.c中实现。</p><p>IDR（ID Radix）机制是将对象的身份鉴别号整数值ID与对象指针建立关联表，完成从ID与指针之间的相互转换。IDR机制使用radix树状结构作为由id进行索引获取指针的稀疏数组，通过使用位图可以快速分配新的ID，IDR机制避免了使用固定尺寸的数组存放指针。IDR机制的API函数在lib/idr.c中实现。</p><p>Linux内核利用radix树在文件内偏移快速定位文件缓存页。 Linux(2.6.7) 内核中的分叉为 64()，树高为 6(64位系统)或者 11(32位系统)，用来快速定位 32 位或者 64 位偏移，radix tree 中的每一个叶子节点指向文件内相应偏移所对应的Cache项。</p><p>【radix树为稀疏树提供了有效的存储，代替固定尺寸数组提供了键值到指针的快速查找。】</p><h2 id="_4-总结" tabindex="-1">4. 总结 <a class="header-anchor" href="#_4-总结" aria-label="Permalink to &quot;4. 总结&quot;">​</a></h2><p>Radix树与Trie树的思想有点类似，甚至可以把Trie树看为一个基为26的Radix树。（也可以把Radix树看做是Tire树的变异）</p><p>Trie树一般用于字符串到对象的映射，Radix树一般用于长整数到对象的映射。</p><p>trie树主要问题是树的层高，如果要索引的字的拼音很长很变态，我们也要建一个很高很变态的树么？</p><p>radix树能固定层高（对于较长的字符串，可以用数学公式计算出其特征值，再用radix树存储这些特征值）</p>',26),l=[d];function o(p,s,h,n,x,c){return r(),e("div",null,l)}const T=a(t,[["render",o]]);export{R as __pageData,T as default};
